## 2. Networking

### 2.1 Network Topology Design

Network architecture for Apple Silicon distributed systems must account for the physical limitations of Mac hardware while maximizing throughput. We recommend a hierarchical topology:

```
                        ┌─────────────────┐
                        │   Load Balancer │
                        │   (Software)    │
                        └────────┬────────┘
                                 │
          ┌──────────────────────┼──────────────────────┐
          │                      │                      │
          ▼                      ▼                      ▼
   ┌─────────────┐       ┌─────────────┐       ┌─────────────┐
   │   Node 1    │       │   Node 2    │       │   Node 3    │
   │ 192.168.1.10│◄─────►│ 192.168.1.11│◄─────►│ 192.168.1.12│
   │             │ gRPC  │             │ gRPC  │             │
   └─────────────┘       └─────────────┘       └─────────────┘
          │                      │                      │
          └──────────────────────┼──────────────────────┘
                                 │
                                 ▼
                    ┌─────────────────────────┐
                    │   Inter-node Consensus  │
                    │   (Dedicated Ports)     │
                    └─────────────────────────┘
```

Key networking principles:

1. **Dedicated Consensus Ports**: Separate ports for consensus traffic (typically 8081) and client traffic (8080) allow independent scaling and QoS management.
2. **gRPC for Inter-Node Communication**: We use gRPC with Protocol Buffers for efficient serialization and built-in streaming capabilities.
3. **HTTP/1.1 for Client API**: REST-style endpoints for client compatibility, with HTTP/2 under the hood for multiplexing.

### 2.2 Network Transport Implementation

```swift
import Foundation
import NIO
import NIOSSL
import Logging

/// Network transport layer handling all inter-node and client communication
public final class NetworkTransport: @unchecked Sendable {
    private let eventLoopGroup: MultiThreadedEventLoopGroup
    private let serverBootstrap: ServerBootstrap
    private let clientBootstrap: ClientBootstrap
    private let channel: Channel?

    private let listenAddress: String
    private let port: Int
    private let consensusPort: Int

    private let logger: Logger
    private var activeConnections = Set<Channel>()
    private let connectionLock = NSLock()

    public init(
        eventLoopGroup: MultiThreadedEventLoopGroup,
        listenAddress: String,
        port: Int,
        consensusPort: Int
    ) {
        self.eventLoopGroup = eventLoopGroup
        self.listenAddress = listenAddress
        self.port = port
        self.consensusPort = consensusPort

        var logger = Logger(label: "com.distributed.transport")
        logger.logLevel = .info
        self.logger = logger

        // Configure server bootstrap optimized for Apple Silicon
        self.serverBootstrap = ServerBootstrap(group: eventLoopGroup)
            .serverChannelOption(ChannelOptions.backlog, value: 256)
            .serverChannelOption(ChannelOptions.socketOption(.so_reuseaddr), value: 1)
            .serverChannelOption(ChannelOptions.maxMessagesPerRead, value: 16)
            .serverChannelOption(ChannelOptions.recvAllocator, value: AdaptiveRecvByteBufferAllocator())
            .childChannelInitializer { channel in
                // Add timeout and idle state handlers
                let idleHandler = IdleStateHandler(
                    readTimeout: .seconds(30),
                    writeTimeout: .seconds(10),
                    allTimeout: .seconds(60)
                )

                return channel.pipeline.addHandler(idleHandler).flatMap {
                    // Add protobuf codec
                    let protobufHandler = ProtobufPacketHandler()
                    return channel.pipeline.addHandler(protobufHandler)
                }
            }
            .childChannelOption(ChannelOptions.socketOption(.so_reuseaddr), value: 1)
            .childChannelOption(ChannelOptions.maxMessagesPerRead, value: 16)
            .childChannelOption(ChannelOptions.recvAllocator, value: AdaptiveRecvByteBufferAllocator())
            .childChannelOption(ChannelOptions.writeBufferWaterMark, low: 32 * 1024, high: 128 * 1024)

        // Configure client bootstrap
        self.clientBootstrap = ClientBootstrap(group: eventLoopGroup)
            .channelOption(ChannelOptions.socketOption(.so_reuseaddr), value: 1)
            .channelOption(ChannelOptions.maxMessagesPerRead, value: 16)
            .channelOption(ChannelOptions.recvAllocator, value: AdaptiveRecvByteBufferAllocator())
            .channelOption(ChannelOptions.connectTimeout, value: .seconds(10))
    }

    public func start() async throws {
        let channel = try await serverBootstrap.bind(host: listenAddress, port: port).get()
        self.channel = channel
        logger.info("Transport started on \(listenAddress):\(port)")
    }

    /// Send message to specific node with retry logic
    public func sendMessage(
        to address: String,
        port: Int,
        message: NetworkMessage,
        retryCount: Int = 3
    ) async throws -> NetworkMessage {
        var lastError: Error?

        for attempt in 0..<retryCount {
            do {
                let channel = try await connect(to: address, port: port)
                try await channel.writeAndFlush(message)

                // Wait for response with timeout
                let response = try await withTimeout(seconds: 5) {
                    await self.waitForResponse(on: channel)
                }

                return response
            } catch {
                lastError = error
                logger.warning("Send attempt \(attempt + 1) failed: \(error)")

                // Exponential backoff
                try await Task.sleep(nanoseconds: UInt64(pow(2.0, Double(attempt))) * 1_000_000_000)
            }
        }

        throw NetworkError.deliveryFailed(lastError ?? NSError(domain: "Network", code: -1))
    }

    /// Broadcast message to all known peers
    public func broadcast(
        message: NetworkMessage,
        to peers: [PeerAddress]
    ) async throws -> [PeerAddress: NetworkMessage] {
        try await withThrowingTaskGroup(of: (PeerAddress, NetworkMessage).self) { group in
            for peer in peers {
                group.addTask {
                    let response = try await self.sendMessage(
                        to: peer.address,
                        port: peer.consensusPort,
                        message: message
                    )
                    return (peer, response)
                }
            }

            var results: [PeerAddress: NetworkMessage] = [:]
            for try await (peer, response) in group {
                results[peer] = response
            }
            return results
        }
    }
}
```

### 2.3 Service Discovery

Service discovery enables nodes to find each other dynamically:

```swift
import Foundation
import NIO

/// Peer address representation
public struct PeerAddress: Hashable, Codable, Sendable {
    public let nodeId: UUID
    public let address: String
    public let port: Int
    public let consensusPort: Int
    public let isLeader: Bool

    public init(nodeId: UUID, address: String, port: Int, consensusPort: Int, isLeader: Bool = false) {
        self.nodeId = nodeId
        self.address = address
        self.port = port
        self.consensusPort = consensusPort
        self.isLeader = isLeader
    }
}

/// Service discovery module using gossip protocol
public final class ServiceDiscovery: @unchecked Sendable {
    private let nodeId: UUID
    private let eventLoopGroup: MultiThreadedEventLoopGroup
    private var peers: [UUID: PeerAddress] = [:]
    private let peersLock = NSLock()

    private var gossipTimer: RepeatedTask?
    private let gossipInterval: TimeAmount = .seconds(3)

    private let logger: Logger

    public init(nodeId: UUID, eventLoopGroup: MultiThreadedEventLoopGroup) {
        self.nodeId = nodeId
        self.eventLoopGroup = eventLoopGroup

        var logger = Logger(label: "com.distributed.discovery")
        logger.logLevel = .debug
        self.logger = logger
    }

    /// Register a new peer in the cluster
    public func registerPeer(_ peer: PeerAddress) {
        peersLock.lock()
        defer { peersLock.unlock() }

        let existingPeer = peers[peer.nodeId]
        peers[peer.nodeId] = peer

        if existingPeer == nil {
            logger.info("Registered new peer: \(peer.nodeId) at \(peer.address):\(peer.port)")
        } else {
            logger.debug("Updated peer: \(peer.nodeId)")
        }
    }

    /// Remove peer from cluster
    public func removePeer(nodeId: UUID) {
        peersLock.lock()
        defer { peersLock.unlock() }

        if peers.removeValue(forKey: nodeId) != nil {
            logger.info("Removed peer: \(nodeId)")
        }
    }

    /// Get all known peers
    public func getAllPeers() -> [PeerAddress] {
        peersLock.lock()
        defer { peersLock.unlock() }
        return Array(peers.values)
    }

    /// Get current leader if known
    public func getLeader() -> PeerAddress? {
        peersLock.lock()
        defer { peersLock.unlock() }
        return peers.values.first { $0.isLeader }
    }

    /// Start gossip protocol for peer information exchange
    public func startGossip(existingPeers: [PeerAddress]) {
        for peer in existingPeers {
            registerPeer(peer)
        }

        gossipTimer = eventLoopGroup.next().scheduleRepeatedTask(
            initialDelay: gossipInterval,
            delay: gossipInterval
        ) { [weak self] _ in
            Task {
                await self?.performGossipRound()
            }
        }

        logger.info("Gossip protocol started")
    }

    private func performGossipRound() async {
        peersLock.lock()
        let currentPeers = Array(peers.values)
        peersLock.unlock()

        guard currentPeers.count > 1 else { return }

        // Select random peers for gossip (typically 3)
        let selectedPeers = Array(currentPeers.shuffled().prefix(3))

        for peer in selectedPeers where peer.nodeId != nodeId {
            do {
                let gossipMessage = GossipMessage(
                    senderId: nodeId,
                    peerList: currentPeers.map { PeerInfo(from: $0) },
                    timestamp: Date()
                )

                // Send gossip and merge received peers
                let response = try await sendGossip(
                    to: peer.address,
                    port: peer.consensusPort,
                    message: gossipMessage
                )

                await mergePeerInfo(response.peerList)
            } catch {
                logger.debug("Gossip exchange with \(peer.nodeId) failed: \(error)")
            }
        }
    }

    private func mergePeerInfo(_ incomingPeers: [PeerInfo]) async {
        peersLock.lock()

        for peerInfo in incomingPeers {
            let peer = PeerAddress(
                nodeId: peerInfo.nodeId,
                address: peerInfo.address,
                port: peerInfo.port,
                consensusPort: peerInfo.consensusPort,
                isLeader: peerInfo.isLeader
            )

            // Merge: keep newer information
            if let existing = peers[peer.nodeId] {
                if peerInfo.timestamp > Date() { // Simplified comparison
                    peers[peer.nodeId] = peer
                }
            } else {
                peers[peer.nodeId] = peer
            }
        }

        peersLock.unlock()
    }
}
```

