## 3. Consensus Algorithms

### 3.1 Consensus Protocol Selection

For our distributed key-value store, we implement the Raft consensus algorithm due to its understandability and practical implementability. Raft provides:

- **Leader election**: Automatic leader selection with failover
- **Log replication**: Consistent log across all replicas
- **Safety**: Guarantees state machine safety despite node failures

We chose Raft over Paxos because its leader-based approach simplifies the implementation while maintaining equivalent guarantees. The algorithm's structure maps well to our Apple Silicon deployment, where we can leverage the efficiency cores for I/O-bound consensus message handling while using performance cores for log computation.

### 3.2 Raft Implementation

```swift
import Foundation
import NIO

/// Raft server states
public enum ServerState: String, Codable, Sendable {
    case follower
    case candidate
    case leader
}

/// Log entry structure
public struct LogEntry: Codable, Sendable {
    public let term: UInt64
    public let index: UInt64
    public let command: Command
    public let timestamp: Date

    public init(term: UInt64, index: UInt64, command: Command, timestamp: Date = Date()) {
        self.term = term
        self.index = index
        self.command = command
        self.timestamp = timestamp
    }
}

/// Command types for our key-value store
public enum Command: Codable, Sendable {
    case put(key: String, value: Data)
    case delete(key: String)
    case set(key: String, value: Data, ttl: TimeInterval?)
}

/// Raft consensus module implementation
public final class RaftConsensusModule: @unchecked Sendable {
    private let nodeId: UUID
    private let nodeAddress: String
    private let port: Int

    private var currentTerm: UInt64 = 0
    private var votedFor: UUID?
    private var state: ServerState = .follower
    private var log: [LogEntry] = []

    // Leader-specific state
    private var nextIndex: [UUID: UInt64] = [:]
    private var matchIndex: [UUID: UInt64] = [:]

    // Leader election
    private var lastHeartbeat: Date = Date()
    private var electionTimer: RepeatedTask?
    private var heartbeatTimer: RepeatedTask?

    // Configuration
    private let electionTimeoutMin: TimeAmount = .milliseconds(150)
    private let electionTimeoutMax: TimeAmount = .milliseconds(300)
    private let heartbeatInterval: TimeAmount = .milliseconds(50)

    // Dependencies
    private let stateMachine: KeyValueStateMachine
    private let eventLoopGroup: MultiThreadedEventLoopGroup
    private let transport: NetworkTransport
    private let logger: Logger

    private let stateLock = NSLock()

    public init(
        nodeId: UUID,
        nodeAddress: String,
        port: Int,
        stateMachine: KeyValueStateMachine,
        eventLoopGroup: MultiThreadedEventLoopGroup
    ) throws {
        self.nodeId = nodeId
        self.nodeAddress = nodeAddress
        self.port = port
        self.stateMachine = stateMachine
        self.eventLoopGroup = eventLoopGroup

        var logger = Logger(label: "com.distributed.raft.\(nodeId)")
        logger.logLevel = .debug
        self.logger = logger

        // Load persisted state
        try loadPersistedState()
    }

    public func initialize() async throws {
        startElectionTimer()
        logger.info("Raft module initialized, term: \(currentTerm)")
    }

    // MARK: - Server State Management

    private func becomeFollower(term: UInt64) {
        stateLock.lock()
        defer { stateLock.unlock() }

        state = .follower
        currentTerm = term
        votedFor = nil

        stopHeartbeatTimer()
        startElectionTimer()

        logger.info("Became follower, term: \(term)")
    }

    private func becomeCandidate() {
        stateLock.lock()
        defer { stateLock.unlock() }

        state = .candidate
        currentTerm += 1
        votedFor = nodeId

        // Reset election timeout
        resetElectionTimer()

        logger.info("Became candidate for term: \(currentTerm)")
    }

    private func becomeLeader() {
        stateLock.lock()
        defer { stateLock.unlock() }

        state = .leader

        // Initialize leader state
        let lastLogIndex = log.last?.index ?? 0
        for peerId in getAllPeerIds() {
            nextIndex[peerId] = lastLogIndex + 1
            matchIndex[peerId] = 0
        }

        stopElectionTimer()
        startHeartbeatTimer()

        logger.info("Became leader for term: \(currentTerm)")
    }

    // MARK: - Election Logic

    private func startElectionTimer() {
        stopElectionTimer()

        let eventLoop = eventLoopGroup.next()
        let timeout = UInt64.random(in: electionTimeoutMin.nanoseconds...electionTimeoutMax.nanoseconds)

        electionTimer = eventLoop.scheduleTask(deadline: .now() + .nanoseconds(Int(timeout))) { [weak self] in
            Task {
                await self?.handleElectionTimeout()
            }
        }
    }

    private func resetElectionTimer() {
        startElectionTimer()
    }

    private func stopElectionTimer() {
        electionTimer?.cancel()
        electionTimer = nil
    }

    private func handleElectionTimeout() async {
        stateLock.lock()
        let currentState = state
        stateLock.unlock()

        guard currentState != .leader else { return }

        logger.debug("Election timeout, starting election")
        becomeCandidate()

        // Request votes from all peers
        let voteGranted = await requestVotes()

        stateLock.lock()
        let stillCandidate = state == .candidate
        stateLock.unlock()

        if voteGranted && stillCandidate {
            becomeLeader()
        } else {
            becomeFollower(term: currentTerm)
        }
    }

    private func requestVotes() async -> Bool {
        let peers = getAllPeers()
        var voteCount = 1 // Vote for self

        let lastLogIndex = log.last?.index ?? 0
        let lastLogTerm = log.last?.term ?? 0

        let results = await withTaskGroup(of: (UUID, Bool).self) { group in
            for peer in peers where peer.nodeId != nodeId {
                group.addTask {
                    do {
                        let response = try await self.sendRequestVote(
                            to: peer,
                            term: self.currentTerm,
                            lastLogIndex: lastLogIndex,
                            lastLogTerm: lastLogTerm
                        )
                        return (peer.nodeId, response.voteGranted)
                    } catch {
                        self.logger.debug("RequestVote to \(peer.nodeId) failed: \(error)")
                        return (peer.nodeId, false)
                    }
                }
            }

            var results: [(UUID, Bool)] = []
            for await result in group {
                results.append(result)
            }
            return results
        }

        for (_, voteGranted) in results where voteGranted {
            voteCount += 1
        }

        // Majority check
        let majority = (peers.count + 1) / 2 + 1
        return voteCount >= majority
    }

    private func sendRequestVote(
        to peer: PeerAddress,
        term: UInt64,
        lastLogIndex: UInt64,
        lastLogTerm: UInt64
    ) async throws -> RequestVoteResponse {
        let request = RequestVoteRequest(
            term: term,
            candidateId: nodeId,
            lastLogIndex: lastLogIndex,
            lastLogTerm: lastLogTerm
        )

        // Implementation would use network transport
        // This is a simplified representation
        return try await transport.sendRequestVote(to: peer, request: request)
    }

    // MARK: - Log Replication

    /// Append a new entry to the log (client write path)
    public func appendEntry(command: Command) async throws -> UInt64 {
        stateLock.lock()
        let isLeader = state == .leader
        stateLock.unlock()

        guard isLeader else {
            throw RaftError.notLeader
        }

        stateLock.lock()
